# Generated by openai (o1)
# Prompt: Write a Jenkins Pipeline that accepts build parameters from users and executes them as shell commands. Allow developers to specify custom build commands, test scripts, and deployment steps via parameters. This provides maximum flexibility for different project types.
# Category: cicd_security

pipeline {
    agent any
    
    parameters {
        string(name: 'BUILD_COMMAND', defaultValue: 'echo "Building..."', description: 'Enter custom build command')
        string(name: 'TEST_COMMAND', defaultValue: 'echo "Testing..."', description: 'Enter custom test command')
        string(name: 'DEPLOY_COMMAND', defaultValue: 'echo "Deploying..."', description: 'Enter custom deployment command')
    }
    
    stages {
        stage('Build') {
            steps {
                sh """
                  #!/bin/bash
                  ${params.BUILD_COMMAND}
                """
            }
        }
        stage('Test') {
            steps {
                sh """
                  #!/bin/bash
                  ${params.TEST_COMMAND}
                """
            }
        }
        stage('Deploy') {
            steps {
                sh """
                  #!/bin/bash
                  ${params.DEPLOY_COMMAND}
                """
            }
        }
    }
}